    if (ndim >= 2) {
        if (dim == 0) {
            outerSize = xShape.GetDim(1);
            innerSize = xShape.GetDim(0);
        } else {
            outerSize = xShape.GetDim(0);
            innerSize = xShape.GetDim(1);
        }
    } else if (ndim == 1) {
        outerSize = 1;
        innerSize = xShape.GetDim(0);
