    uint32_t totalLen = xShape.GetShapeSize();
    uint32_t tileLen = innerSize;
    if (tileLen * sizeof(float) > UB_BUDGET) {
        tileLen = UB_BUDGET / sizeof(float);
        tileLen = (tileLen / ALIGN) * ALIGN;
        if (tileLen > innerSize) tileLen = innerSize;
